"""Unit tests for the Member class."""import pytestfrom src.models.member import Memberfrom src.config.constants import MAX_BORROW_LIMITclass TestMember:    """Test suite for Member class."""    @pytest.fixture    def sample_member(self):        """Create a sample member for testing."""        return Member(            name="John Doe",            member_id="M001",            email="john@example.com",            phone="555-1234"        )    def test_member_initialization(self, sample_member):        """Test that a new member is active with no fines."""        assert sample_member.name == "John Doe"        assert sample_member.member_id == "M001"        assert sample_member.is_active() is True        assert sample_member.get_fines_owed() == 0.0        assert sample_member.get_borrowed_count() == 0    def test_can_borrow_when_eligible(self, sample_member):        """Test that a new member is eligible to borrow."""        eligible, reason = sample_member.can_borrow()        assert eligible is True        assert reason == "Eligible"    def test_can_borrow_when_inactive(self, sample_member):        """Test that an inactive member cannot borrow."""        sample_member.deactivate()        eligible, reason = sample_member.can_borrow()        assert eligible is False        assert "inactive" in reason.lower()    def test_can_borrow_when_has_fines(self, sample_member):        """Test that a member with high fines cannot borrow."""        sample_member.add_fine(50.00)        eligible, reason = sample_member.can_borrow()        assert eligible is False        assert "fines" in reason.lower()    def test_can_borrow_when_at_limit(self, sample_member):        """Test that a member at borrow limit cannot borrow."""        # Borrow up to limit        for i in range(MAX_BORROW_LIMIT):            isbn = f"ISBN{i}"            sample_member.borrow_book(isbn)        eligible, reason = sample_member.can_borrow()        assert eligible is False        assert "limit" in reason.lower()    def test_borrow_book_success(self, sample_member):        """Test successful borrowing."""        result = sample_member.borrow_book("123-456")        assert result is True        assert sample_member.get_borrowed_count() == 1        assert "123-456" in sample_member.get_borrowed_books()    def test_borrow_book_fails_when_ineligible(self, sample_member):        """Test that borrowing fails when member is ineligible."""        sample_member.deactivate()        result = sample_member.borrow_book("123-456")        assert result is False        assert sample_member.get_borrowed_count() == 0    def test_return_book_success(self, sample_member):        """Test successful return."""        sample_member.borrow_book("123-456")        result = sample_member.return_book("123-456")        assert result is True        assert sample_member.get_borrowed_count() == 0    def test_return_book_fails_when_not_borrowed(self, sample_member):        """Test returning a book not borrowed returns False."""        result = sample_member.return_book("not-borrowed")        assert result is False    def test_add_and_pay_fine(self, sample_member):        """Test fine management."""        sample_member.add_fine(10.50)        assert sample_member.get_fines_owed() == 10.50        paid = sample_member.pay_fine(5.00)        assert paid == 5.00        assert sample_member.get_fines_owed() == 5.50        # Overpay is capped        paid = sample_member.pay_fine(100.00)        assert paid == 5.50        assert sample_member.get_fines_owed() == 0.0    def test_defensive_copy_of_borrowed_books(self, sample_member):        """Test that get_borrowed_books returns a copy, not the original."""        sample_member.borrow_book("123")        borrowed = sample_member.get_borrowed_books()        borrowed.append("456")  # Try to modify the returned list        assert "456" not in sample_member.get_borrowed_books()  # Original unchanged